parameters.jsCode:
const texto = $input.first().json.texto || "sem texto";
const sentimento = $input.first().json.sentimento || "desconhecido";
const intensidade = $input.first().json.intensidade || "normal";
const score = $input.first().json.score || 50;
const data = new Date().toISOString();

const linha = `${data},"${texto}",${sentimento}\n`;

return [{ json: { csv_linha: linha, texto, sentimento, intensidade, score } }];

const updates = $input.first().json.result || [];
const agora = Math.floor(Date.now() / 1000);
const doisMinutosAtras = agora - 120;

const filtradas = updates.filter(u =>
  u.message?.text &&
  u.message.text.trim().length > 0 &&
  !u.message.text.startsWith('/') &&
  u.message?.date >= doisMinutosAtras
);

if (filtradas.length === 0) return [];

return filtradas.map(u => ({
  json: {
    chatId: u.message.chat.id,
    query: {
      texto: u.message.text.trim()
    }
  }
}));

